
import {Time} from "animation-utilities";

/**
 * @typedef jibo.lps#LPSVisualEntityTypes
 * @description Enum of Visual ID types
 * @prop PERSON {any} Person identified.
 * @prop MOTION {any} Motion identified.
 */
export enum LPSVisualEntityTypes {
    PERSON = <any> "person",
    MOTION = <any> "motion",
    WAKE = <any> "wake"
};

/**
 * @typedef jibo.lps#PositionInSpace
 * @description 3D point in space.
 * @prop x {number} Meters forward.
 * @prop y {number} Meters left.
 * @prop z {number} Meters up.
 */
export interface PositionInSpace {
    x: number;
    y: number;
    z: number;
}

/**
 * @typedef jibo.lps#IDSummary
 * @description Summary of attributes an entity identified by LPS
 * @prop {String} name Best available estimate of identity. May be `UNKNOWN` because LPS does not know or `NOT_TRAINED` if not in loop.
 * @prop {String} kind Usually the primary kind of identification like `face` or `voice` or `fused`.
 * @prop {Number} confidence `[0,1]` confidence in the summary identification.
 * @prop {any} ts Timestamp of when summary last updated.
 */
export interface IDSummary {
    name: string;
    kind: string;
    confidence: number;
    ts: any;
}

/**
 * @typedef jibo.lps#LPSEntity
 * @description All attributes of incoming entities from LPS Service.
 * @prop {string} id UUID of LPS system mapping to entity, including looper ID if recognized.
 * @prop {number} confidence Confidence in the information about the entity.
 * @prop {jibo.lps#LPSVisualEntityTypes} description Description of the entity.
 * @prop {string} extent Length of the object in each axis.
 * @prop {jibo.lps#IDSummary} id_summary Summary of attributes of entity.
 * @prop {string} identity_inputs Map of Identity hypotheses from multiple sources.
 * @prop {boolean} in_fov  Is Entity in the FOV / frustrum of cameras.
 * @prop {jibo.animate.Time} last_measured Timestamp of when entity was last measured.
 * @prop {boolean} occluded Set when occluded by other entity.
 * @prop {jibo.lps#PositionInSpace} orientation Rotation about each axis in radians.
 * @prop {string} parts Parts that compose the entity.
 * @prop {jibo.lps#PositionInSpace} position Position in world space.
 * @prop {boolean} static Whether the item is static or not.
 * @prop {string} tags Open set of tags for this entity used for things like emotional state, etc.
 * @prop {string} velocity Velocity that the entity is moving.
 */
export interface LPSEntity{
    confidence: number;
    description: LPSVisualEntityTypes;
    extent: string;
    id: string;
    id_summary: IDSummary;
    identity_inputs: string;
    in_fov: boolean;
    last_measured: Time;
    occluded: boolean;
    orientation: PositionInSpace;
    parts: string;
    position: PositionInSpace;
    static: boolean;
    tags: string;
    velocity: string;
}
