
/**
 * @description The state of jibo's body.
 * @class BodyState
 * @memberof jibo.system
 */
export class BodyState {
    /**
     * Miscellaneous body state information
     * @name jibo.system.BodyState#miscState
     * @type {jibo.system.MiscState}
     */
    public miscState: MiscState;
    /**
     * Touch pad state information
     * @name jibo.system.BodyState#touchState
     * @type {jibo.system.TouchState}
     */
    public touchState: TouchState;
    /**
     * Power state information
     * @name jibo.system.BodyState#powerState
     * @type {jibo.system.PowerState}
     */
    public powerState: PowerState;

    constructor() {
        this.miscState = new MiscState();
        this.touchState = new TouchState();
        this.powerState = new PowerState();
    }
}

/**
 * @description Miscellaneous body state information.
 * @class MiscState
 * @memberof jibo.system
 */
export class MiscState {
    /**
     * Chronometer timestamp
     * @name jibo.system.MiscState#ts
     * @type {Array<any>}
     */
    public ts:any[];
    /**
     * Main board temperature sensor in degrees Celsius
     * @name jibo.system.MiscState#main_board_temp
     * @type {number}
     */
    public main_board_temp:number;
    /**
     * CPU die temperature in degrees Celsius
     * @name jibo.system.MiscState#cpu_temp
     * @type {number}
     */
    public cpu_temp:number;
    /**
     * Cooling air intake temperature in degrees Celsius
     * @name jibo.system.MiscState#intake_temp
     * @type {number}
     */
    public intake_temp:number;
    /**
     * Cooling air exhaust temperature in degrees Celsius
     * @name jibo.system.MiscState#exhaust_temp
     * @type {number}
     */
    public exhaust_temp:number;
    /**
     * Head motor temperature in degrees Celsius
     * @name jibo.system.MiscState#neck_motor_temp
     * @type {number}
     */
    public neck_motor_temp:number;
    /**
     * Torso motor temperature in degrees Celsius
     * @name jibo.system.MiscState#torso_motor_temp
     * @type {number}
     */
    public torso_motor_temp:number;
    /**
     * Pelvis motor temperature in degrees Celsius
     * @name jibo.system.MiscState#pelvis_motor_temp
     * @type {number}
     */
    public pelvis_motor_temp:number;

    constructor() {
        this.ts = [];
        this.main_board_temp = 0;
        this.cpu_temp = 0;
        this.intake_temp = 0;
        this.exhaust_temp = 0;
        this.neck_motor_temp = 0;
        this.torso_motor_temp = 0;
        this.pelvis_motor_temp = 0;
    }
}

/**
 * @description The state of Jibo's head touchpads.
 * @class TouchState
 * @memberof jibo.system
 */
export class TouchState {
    /**
     * Chronometer timestamp.
     * @name jibo.system.TouchState#ts
     * @type {Array<number>}
     */
    public ts : number[];
    /**
     * `true` if any of the pads have been touched.
     * @name jibo.system.TouchState#touched
     * @type {boolean}
     */
    public touched : boolean;
    /**
     * The array of the 6 pads with `true` for touched and `false` for not touched.
     *
     * See {@tutorial robot-info-tool} for a diagram of Jibo's head touch pads.
     *
     * Three run vertically down the left side of Jibo's head from top to bottom: `pad_state[0, 1, 2]`.
     *
     * Three run vertically down the right of his head: `pad_state[3, 4, 5]`.
     * @name jibo.system.TouchState#pad_state
     * @type {Array<boolean>}
     */
    public pad_state : boolean[];
    /**
     * Array with the indices of the pads that changed in this update. Empty if none.
     * @name jibo.system.TouchState#changed
     * @type {Array<number>}
     */
    public changed: number[];

    constructor() {
        this.ts = [];
        this.touched = false;
        this.pad_state = [false, false, false, false, false, false];
        this.changed = [0,0,0,0,0,0];
    }
}

/**
 * @description Power state information.
 * @class PowerState
 * @memberof jibo.system
 */
export class PowerState {
    /**
     * Chronometer timestamp.
     * @name jibo.system.PowerState#ts
     * @type {Array<number>}
     */
    public ts: any[];
    /**
     * Are we on `'BATTERY'` or `'EXTERNAL'`.
     * @name jibo.system.PowerState#source
     * @type {String}
     */
    public source: string;
    /**
     * The current system voltage estimate.
     * @name jibo.system.PowerState#vsys
     * @type {number}
     */
    public vsys  : number;
    /**
     * Battery object, or undefined if no battery is present or detected.
     * @name jibo.system.PowerState#battery
     * @type {jibo.system.BatteryState}
     */
    public battery : BatteryState;

    constructor() {
        this.ts = [];
        this.source = "";
        this.vsys  = 0;
        this.battery = new BatteryState();
    }
}

/**
 * @description The state of Jibo's battery.
 * @class BatteryState
 * @memberof jibo.system
 */
export class BatteryState {
    /**
     * Battery ID.
     * @name jibo.system.BatteryState#id
     * @type {number}
     */
    public id : number;
    /**
     * Number of battery cycles on this battery.
     * @name jibo.system.BatteryState#cycles
     * @type {number}
     */
    public cycles : number;
    /**
     * Current capacity of this battery in amp hours.
     * @name jibo.system.BatteryState#capacity
     * @type {number}
     */
    public capacity : number;
    /**
     * Maximum capacity of this battery in amp hours.
     * @name jibo.system.BatteryState#max_capacity
     * @type {number}
     */
    public max_capacity : number;
    /**
     * Charge rate of battery. Negative if draining. Positive if charging.
     * @name jibo.system.BatteryState#charge_rate
     * @type {number}
     */
    public charge_rate: number;
    /**
     * Battery temperature in degrees Celsius.
     * @name jibo.system.BatteryState#temp
     * @type {number}
     */
    public temp : number;

    constructor() {
        this.id = 0;
        this.cycles = 0;
        this.capacity = 0;
        this.max_capacity = 0;
        this.charge_rate= 0;
        this.temp = 0;
    }
}

/**
 * @description Input Energy as sensed by Jibo.
 * @class InputEnergy
 * @memberof jibo.system
 */
export class InputEnergy {
    /**
     * Chronometer timestamp of this state.
     * @name jibo.system.InputEnergy#ts
     * @type {Array<number>}
     */
    public ts: any[];
    /**
     * Overall dB RMS of input waveform.
     * @name jibo.system.InputEnergy#db_rms
     * @type {number}
     */
    public db_rms: number;
    /**
     *  ~1KHz dB RMS of input waveform.
     * @name jibo.system.InputEnergy#db_high
     * @type {number}
     */
    public db_high: number;
    /**
     *  ~500Hz dB RMS of input waveform.
     * @name jibo.system.InputEnergy#db_mid
     * @type {number}
     */
    public db_mid: number;
    /**
     * ~200Hz dB RMS of input waveform.
     * @name jibo.system.InputEnergy#db_low
     * @type {number}
     */
    public db_low: number;

    constructor() {
        this.ts = [null,null];
        this.db_rms = null;
        this.db_high = null;
        this.db_mid = null;
        this.db_low = null;
    }
}
